import scala.collection.mutable

def solve(n: Long, edges: Array[Array[Long]]): Long = {
  val graph = mutable.HashMap[Long, List[(Long, Long)]]()
  for (edge <- edges) {
    val u = edge(0)
    val v = edge(1)
    val w = edge(2)
    graph.getOrElseUpdate(u, Nil) ::= (v, w)
  }

  val dist = mutable.HashMap[(Long, Boolean), Long]()
  val heap = mutable.PriorityQueue[(Long, Long, Boolean)]()
  heap.enqueue((0L, 0L, false))
  dist((0L, false)) = 0L

  while (heap.nonEmpty) {
    val (cost, node, switchUsed) = heap.dequeue()
    val key = (node, switchUsed)
    if (dist(key) < cost) continue

    if (node == n - 1) return cost

    for ((v, w) <- graph.getOrElse(node, Nil)) {
      val newCost = cost + w
      val newKey = (v, false)
      if (dist.getOrElse(newKey, Long.MaxValue) > newCost) {
        dist(newKey) = newCost
        heap.enqueue((newCost, v, false))
      }

      if (!switchUsed) {
        val flipCost = cost + 2 * w
        val flipKey = (v, true)
        if (dist.getOrElse(flipKey, Long.MaxValue) > flipCost) {
          dist(flipKey) = flipCost
          heap.enqueue((flipCost, v, true))
        }
      }
    }
  }

  -1L
}
